import type { ReactNode } from 'react';

import type { TreeNodeProps } from './TreeNode/TreeNode.types';

export interface TreeProps {
	title?: string;
	size?: 'small' | 'medium' | 'large';
	children?: ReactNode;
	amount?: boolean;
	multiselect?: boolean;
	onChange?: (selected: string[]) => void;
	onExpand?: (event: React.MouseEvent<HTMLElement>, nodeId: string) => void;
	style?: object;
	expandOnArrow?: boolean;
	data?: TreeData[];
}

export interface TreeContextType {
	selectedId: string;
	toggleSingleSelect: (id: string) => void;
	nodes: Nodes;
	registerNode: (node: Node) => void;
	toggleCheckbox: (nodeId: string) => void;
	toggleExpansion: (nodeId: string, event?: React.MouseEvent<HTMLElement>) => void;
	changeTreeParams: (newTreeParams: TreeParams) => void;
	treeParams: TreeParams;
	recursiveExpansion: (nodeId: string) => void;
	deleteNode: (nodeId: string) => void;
}

export interface TreeProviderProps {
	children: ReactNode;
	callback: (selected: string[]) => void;
}

export interface Node {
	id: string;
	checked: CheckboxStatus;
	children: string[];
	expanded: boolean;
	disabled: boolean;
}

export enum CheckboxStatus {
	CHECKED,
	PARTIALLY,
	UNCHECKED,
}

export interface Nodes {
	[key: string]: Node;
}

export interface TreeParams {
	size: 'small' | 'medium' | 'large';
	amount: boolean;
	multiselect: boolean;
	expandOnArrow: boolean;
	onExpandCallback?: (event: React.MouseEvent<HTMLElement>, nodeId: string) => void;
}

// зачем здесь сужение типа?
export interface TreeData extends Omit<TreeNodeProps, 'children'> {
	children?: TreeData[];
}
